arguments.command:
# 检查是否有热更流水线在执行（RunHotUpdatePipeline 参数）
$processes = Get-CimInstance Win32_Process -Filter "Name like 'Unity%'" | Where-Object { $_.CommandLine -like '*RunHotUpdatePipeline*' }
if ($processes) {
    Write-Output "HOTUPDATE_RUNNING"
    $processes | ForEach-Object { "PID=$($_.ProcessId)" }
} else {
    Write-Output "NO_HOTUPDATE_RUNNING"
}

# 检查是否有 Unity Editor 进程（exe名为Unity，且带 -projectpath 参数）
